import{_ as a,o as t,c as s,ag as o}from"./chunks/framework.DbM0IBjv.js";const u=JSON.parse('{"title":"OpenSpec Best Practices and Common Mistakes","description":"","frontmatter":{},"headers":[],"relativePath":"en/guide/openspec/best-practices.md","filePath":"en/guide/openspec/best-practices.md","lastUpdated":1775568446000}'),i={name:"en/guide/openspec/best-practices.md"};function n(r,e,l,c,d,p){return t(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="openspec-best-practices-and-common-mistakes" tabindex="-1">OpenSpec Best Practices and Common Mistakes <a class="header-anchor" href="#openspec-best-practices-and-common-mistakes" aria-label="Permalink to &quot;OpenSpec Best Practices and Common Mistakes&quot;">​</a></h1><h2 id="best-practices" tabindex="-1">Best Practices <a class="header-anchor" href="#best-practices" aria-label="Permalink to &quot;Best Practices&quot;">​</a></h2><h3 id="_1-change-names-should-be-narrow-and-clear" tabindex="-1">1) Change Names Should Be Narrow and Clear <a class="header-anchor" href="#_1-change-names-should-be-narrow-and-clear" aria-label="Permalink to &quot;1) Change Names Should Be Narrow and Clear&quot;">​</a></h3><ul><li>✅ <code>add-order-checkout</code></li><li>❌ <code>optimize-system</code></li></ul><p>The more specific the name, the easier to review and track.</p><h3 id="_2-proposal-should-be-readable-in-2-minutes" tabindex="-1">2) Proposal Should Be Readable in 2 Minutes <a class="header-anchor" href="#_2-proposal-should-be-readable-in-2-minutes" aria-label="Permalink to &quot;2) Proposal Should Be Readable in 2 Minutes&quot;">​</a></h3><p>Must answer at least four things:</p><ol><li>Why (Why do this)</li><li>What (What to do)</li><li>Non-Goals (What not to do)</li><li>Risks (What are the risks)</li></ol><h3 id="_3-write-scenarios-not-feelings-in-specs" tabindex="-1">3) Write &quot;Scenarios&quot;, Not &quot;Feelings&quot; in Specs <a class="header-anchor" href="#_3-write-scenarios-not-feelings-in-specs" aria-label="Permalink to &quot;3) Write &quot;Scenarios&quot;, Not &quot;Feelings&quot; in Specs&quot;">​</a></h3><ul><li>✅ Given/When/Then</li><li>❌ &quot;Page is more friendly&quot; &quot;Experience is better&quot;</li></ul><p>Scenarios are testable, enabling stable implementation.</p><h3 id="_4-tasks-should-be-small-and-ordered" tabindex="-1">4) Tasks Should Be Small and Ordered <a class="header-anchor" href="#_4-tasks-should-be-small-and-ordered" aria-label="Permalink to &quot;4) Tasks Should Be Small and Ordered&quot;">​</a></h3><p>Each task should be completable in 30-90 minutes; later tasks should have clear dependencies on earlier tasks.</p><h3 id="_5-review-specs-before-apply" tabindex="-1">5) Review Specs Before Apply <a class="header-anchor" href="#_5-review-specs-before-apply" aria-label="Permalink to &quot;5) Review Specs Before Apply&quot;">​</a></h3><p><code>/opsx:ff</code> generates quickly, but always manually review proposal/specs/design/tasks before running <code>/opsx:apply</code>.</p><h3 id="_6-separate-planning-and-coding-into-different-sessions" tabindex="-1">6) Separate Planning and Coding into Different Sessions <a class="header-anchor" href="#_6-separate-planning-and-coding-into-different-sessions" aria-label="Permalink to &quot;6) Separate Planning and Coding into Different Sessions&quot;">​</a></h3><p>Long sessions pollute context. After planning is stable, start a new session for implementation; output quality will be higher.</p><h3 id="_7-archive-when-complete" tabindex="-1">7) Archive When Complete <a class="header-anchor" href="#_7-archive-when-complete" aria-label="Permalink to &quot;7) Archive When Complete&quot;">​</a></h3><p><code>/opsx:archive</code> keeps the <code>changes/</code> directory &quot;only containing in-progress changes&quot;.</p><h2 id="common-mistakes" tabindex="-1">Common Mistakes <a class="header-anchor" href="#common-mistakes" aria-label="Permalink to &quot;Common Mistakes&quot;">​</a></h2><h3 id="mistake-1-one-change-includes-too-many-features" tabindex="-1">Mistake 1: One Change Includes Too Many Features <a class="header-anchor" href="#mistake-1-one-change-includes-too-many-features" aria-label="Permalink to &quot;Mistake 1: One Change Includes Too Many Features&quot;">​</a></h3><p><strong>Symptoms:</strong> Task explosion, difficult review, frequent rework.</p><p><strong>Fix:</strong> Split into multiple changes, split by business flow.</p><h3 id="mistake-2-design-written-as-implementation-details" tabindex="-1">Mistake 2: Design Written as Implementation Details <a class="header-anchor" href="#mistake-2-design-written-as-implementation-details" aria-label="Permalink to &quot;Mistake 2: Design Written as Implementation Details&quot;">​</a></h3><p><strong>Symptoms:</strong> design.md full of code snippets, but missing reasoning for choices.</p><p><strong>Fix:</strong> Design should write &quot;why we did this way&quot;, code details go in implementation phase.</p><h3 id="mistake-3-spec-and-code-out-of-sync" tabindex="-1">Mistake 3: Spec and Code Out of Sync <a class="header-anchor" href="#mistake-3-spec-and-code-out-of-sync" aria-label="Permalink to &quot;Mistake 3: Spec and Code Out of Sync&quot;">​</a></h3><p><strong>Symptoms:</strong> Code was changed but docs not updated, subsequent AI continues following old specs.</p><p><strong>Fix:</strong> Run verify + sync specs after each change.</p><h3 id="mistake-4-tasks-have-no-acceptance-criteria" tabindex="-1">Mistake 4: Tasks Have No Acceptance Criteria <a class="header-anchor" href="#mistake-4-tasks-have-no-acceptance-criteria" aria-label="Permalink to &quot;Mistake 4: Tasks Have No Acceptance Criteria&quot;">​</a></h3><p><strong>Symptoms:</strong> Tasks &quot;look complete&quot; but can&#39;t be verified.</p><p><strong>Fix:</strong> Add verifiable outputs to each task (file/API/test result).</p><h2 id="practical-checklist" tabindex="-1">Practical Checklist <a class="header-anchor" href="#practical-checklist" aria-label="Permalink to &quot;Practical Checklist&quot;">​</a></h2><ul><li>[ ] proposal has Why / What / Non-Goals / Risks</li><li>[ ] specs have at least one scenario per requirement</li><li>[ ] tasks order and dependencies are clear</li><li>[ ] manual review completed before apply</li><li>[ ] verify passes before archive</li></ul>',34)])])}const m=a(i,[["render",n]]);export{u as __pageData,m as default};
